var dp = vector<int>(m + 1);
var vis = Vec2<bool>(n + 2, m + 1); // 在 j 容量的情况下，为了拿最大，是否应该使用第 i 个物品
fa(i, 1, n) {
	const var& [w, v] = p[i];
	fb(j, m, w) {
		if (dp[j] <= dp[j - w] + v) // 取等号，是因为要取最大下标
			vis[i][j] = 1; // j 容量下，为了取最大可以装 i 物品
		dp[j] = max(dp[j], dp[j - w] + v);
	}
}
cout << dp[m] << endl;

// 倒推还原路径，看看 i 是否可取
int now = m;
fb(i, n, 1) {
	const var& [w, v] = p[i];
	if (vis[i][now]) {
		cout << i << ' ';
		now -= w;
	}
}
cout << endl;

// 使用 vis 辅助数组
var dp = vector<int>(m + 1);
var vis = Vec2<bool>(n + 2, m + 1); // 在 j 容量的情况下，为了拿最大，是否应该使用第 i 个物品
fb(i, n, 1) { // 为了最小字典序方案，倒序
	const var& [w, v] = p[i];
	fb(j, m, w) {
		if (dp[j] <= dp[j - w] + v) // 取等号，是因为要取最小下标
			vis[i][j] = 1; // j 容量下，为了取最大可以装 i 物品
		dp[j] = max(dp[j], dp[j - w] + v);
	}
}
cout << dp[m] << endl;

// 正序枚举，看看 i 是否可取，可取一定取，这样肯定最小字典序
int now = m;
fa(i, 1, n) {
	const var& [w, v] = p[i];
	if (vis[i][now]) {
		cout << i << ' ';
		now -= w;
	}
}
cout << endl;

// 使用朴素背包
var dp = Vec2<int>(n + 2, m + 1); // 为了回溯方案路径，多开一维
fb(i, n, 1) { // 为了最小字典序方案，倒序
	const var& [w, v] = p[i];
	dp[i] = dp[i + 1];
	fb(j, m, w)
		dp[i][j] = max(dp[i][j], dp[i][j - w] + v);
}
cout << dp[1][m] << endl;

// 正序枚举，看看 i 是否可取
int now_w = m, now_v = dp[1][m];
fa(i, 1, n) {
	const var& [w, v] = p[i];
	if (now_w >= w and dp[i + 1][now_w - w] + v == now_v) {
		cout << i << ' ';
		now_w -= w, now_v -= v;
	}
}
cout << endl;
